-- =============================================================================
-- Block 6 — Read-model views for Skip-generated reports / dashboards.
--
-- These are REPORTING views (prefix `vw_` with an underscore, to distinguish them from CodeGen's
-- per-entity `vw<Entity>` base views). They read the AR subledger's own committed data; downstream
-- reporting (Skip, dashboards) queries them directly. Idempotent (CREATE OR ALTER), additive-only.
--
-- DELIVERED (fully supported by the subledger's own data):
--   vw_TrialBalance_AR      — per Company × GLAccount debit/credit/net over committed JEs
--   vw_JEAuditTrail         — flattened JE + line + account + period + batch for drill-through
--   vw_ARtoGLRecon          — per Company × Period entry-status reconciliation (pending→batched→posted)
--   vw_DimensionPL          — revenue/expense netted by analytical dimension value
--   vw_BatchDispatchStatus  — batch lifecycle + control totals + summary-line count
--   vw_ScheduledJESummary   — scheduled-JE rollup by company / entry-type / status
--
-- DEFERRED (depend on data this subledger does not own yet — documented, not stubbed):
--   vw_AROpenByCustomer / vw_ARAging  — need customer + invoice-level AR (upstream Orders, §C1)
--   vw_SalesTaxLiability              — needs the tax engine's accrued balances (Block 7+)
--   vw_FxExposure                     — FX is computed upstream/Payments (W5 retired, §C1)
--   vw_IntercompanyFlow               — intercompany engine deferred (Block 3 schema only)
--   vw_DefRevRollforward              — needs opening balances (AccountBalance materialization, AD-12 deferred)
-- =============================================================================

CREATE OR ALTER VIEW __mj_BizAppsAccounting.vw_TrialBalance_AR AS
SELECT
    je.CompanyID,
    c.Name                                                        AS CompanyName,
    gl.ID                                                           AS GLAccountID,
    gl.Code                                                         AS GLAccountCode,
    gl.Name                                                         AS GLAccountName,
    gl.AccountType,
    SUM(ISNULL(jel.DebitAmount, 0))                                 AS TotalDebits,
    SUM(ISNULL(jel.CreditAmount, 0))                                AS TotalCredits,
    SUM(ISNULL(jel.DebitAmount, 0)) - SUM(ISNULL(jel.CreditAmount, 0)) AS NetBalance,
    COUNT(DISTINCT je.ID)                                           AS EntryCount
FROM __mj_BizAppsAccounting.JournalEntry je
JOIN __mj_BizAppsAccounting.JournalEntryLine jel ON jel.JournalEntryID = je.ID
JOIN __mj_BizAppsAccounting.GLAccount gl ON gl.ID = jel.GLAccountID
LEFT JOIN __mj.Company c ON c.ID = je.CompanyID
WHERE je.Status IN ('Batched', 'GLPosted')   -- committed to the ledger (excludes still-editable Pending)
GROUP BY je.CompanyID, c.Name, gl.ID, gl.Code, gl.Name, gl.AccountType;
GO

CREATE OR ALTER VIEW __mj_BizAppsAccounting.vw_JEAuditTrail AS
SELECT
    je.ID                  AS JournalEntryID,
    je.EntryNumber,
    je.CompanyID,
    c.Name               AS CompanyName,
    je.EntryType,
    je.Status,
    je.EffectiveDate,
    ap.FiscalYear,
    ap.PeriodType,
    ap.PeriodStart,
    ap.PeriodEnd,
    jel.LineNumber,
    gl.Code                AS GLAccountCode,
    gl.Name                AS GLAccountName,
    gl.AccountType,
    jel.DebitAmount,
    jel.CreditAmount,
    jel.Description        AS LineDescription,
    je.BatchID,
    b.BatchNumber,
    je.GLReferenceID,
    je.GLPostedAt,
    je.ScheduledJournalEntryID
FROM __mj_BizAppsAccounting.JournalEntry je
JOIN __mj_BizAppsAccounting.JournalEntryLine jel ON jel.JournalEntryID = je.ID
JOIN __mj_BizAppsAccounting.GLAccount gl ON gl.ID = jel.GLAccountID
JOIN __mj_BizAppsAccounting.AccountingPeriod ap ON ap.ID = je.AccountingPeriodID
LEFT JOIN __mj_BizAppsAccounting.JournalEntryBatch b ON b.ID = je.BatchID
LEFT JOIN __mj.Company c ON c.ID = je.CompanyID;
GO

CREATE OR ALTER VIEW __mj_BizAppsAccounting.vw_ARtoGLRecon AS
SELECT
    je.CompanyID,
    c.Name                                                  AS CompanyName,
    je.AccountingPeriodID,
    ap.FiscalYear,
    ap.PeriodType,
    ap.PeriodStart,
    SUM(CASE WHEN je.Status = 'Pending'  THEN 1 ELSE 0 END)   AS PendingEntries,
    SUM(CASE WHEN je.Status = 'Batched'  THEN 1 ELSE 0 END)   AS BatchedEntries,
    SUM(CASE WHEN je.Status = 'GLPosted' THEN 1 ELSE 0 END)   AS GLPostedEntries,
    COUNT(*)                                                  AS TotalEntries
FROM __mj_BizAppsAccounting.JournalEntry je
JOIN __mj_BizAppsAccounting.AccountingPeriod ap ON ap.ID = je.AccountingPeriodID
LEFT JOIN __mj.Company c ON c.ID = je.CompanyID
GROUP BY je.CompanyID, c.Name, je.AccountingPeriodID, ap.FiscalYear, ap.PeriodType, ap.PeriodStart;
GO

CREATE OR ALTER VIEW __mj_BizAppsAccounting.vw_DimensionPL AS
SELECT
    je.CompanyID,
    c.Name                                                          AS CompanyName,
    d.ID                                                              AS DimensionID,
    d.Code                                                            AS DimensionCode,
    d.Name                                                            AS DimensionName,
    dv.ID                                                             AS DimensionValueID,
    dv.Code                                                           AS DimensionValueCode,
    dv.Name                                                           AS DimensionValueName,
    gl.AccountType,
    SUM(ISNULL(jel.CreditAmount, 0) - ISNULL(jel.DebitAmount, 0))     AS NetAmount,  -- revenue is credit-positive
    SUM(ISNULL(jel.DebitAmount, 0))                                   AS TotalDebits,
    SUM(ISNULL(jel.CreditAmount, 0))                                  AS TotalCredits
FROM __mj_BizAppsAccounting.JournalEntryLine jel
JOIN __mj_BizAppsAccounting.JournalEntry je ON je.ID = jel.JournalEntryID
JOIN __mj_BizAppsAccounting.GLAccount gl ON gl.ID = jel.GLAccountID
JOIN __mj_BizAppsAccounting.JournalEntryLineDimension jeld ON jeld.JournalEntryLineID = jel.ID
JOIN __mj_BizAppsAccounting.Dimension d ON d.ID = jeld.DimensionID
JOIN __mj_BizAppsAccounting.DimensionValue dv ON dv.ID = jeld.DimensionValueID
LEFT JOIN __mj.Company c ON c.ID = je.CompanyID
WHERE gl.AccountType IN ('Revenue', 'Expense', 'ContraRevenue', 'ContraExpense')
  AND je.Status IN ('Batched', 'GLPosted')
GROUP BY je.CompanyID, c.Name, d.ID, d.Code, d.Name, dv.ID, dv.Code, dv.Name, gl.AccountType;
GO

CREATE OR ALTER VIEW __mj_BizAppsAccounting.vw_BatchDispatchStatus AS
SELECT
    b.ID                AS BatchID,
    b.BatchNumber,
    b.CompanyID,
    c.Name            AS CompanyName,
    b.AccountingPeriodID,
    ap.FiscalYear,
    ap.PeriodType,
    b.TargetSystem,
    b.Status,
    b.TotalEntries,
    b.TotalDebits,
    b.TotalCredits,
    b.ExternalBatchRef,
    b.BatchedAt,
    b.SentAt,
    b.AcknowledgedAt,
    (SELECT COUNT(*) FROM __mj_BizAppsAccounting.JournalEntryBatchLineItem li WHERE li.BatchID = b.ID) AS SummaryLineCount
FROM __mj_BizAppsAccounting.JournalEntryBatch b
JOIN __mj_BizAppsAccounting.AccountingPeriod ap ON ap.ID = b.AccountingPeriodID
LEFT JOIN __mj.Company c ON c.ID = b.CompanyID;
GO

CREATE OR ALTER VIEW __mj_BizAppsAccounting.vw_ScheduledJESummary AS
SELECT
    sje.CompanyID,
    c.Name                              AS CompanyName,
    sje.EntryType,
    sje.Status,
    COUNT(*)                              AS EntryCount,
    SUM(sje.TotalAmount)                  AS TotalAmount,
    MIN(sje.ScheduledEffectiveDate)       AS EarliestEffectiveDate,
    MAX(sje.ScheduledEffectiveDate)       AS LatestEffectiveDate
FROM __mj_BizAppsAccounting.ScheduledJournalEntry sje
LEFT JOIN __mj.Company c ON c.ID = sje.CompanyID
GROUP BY sje.CompanyID, c.Name, sje.EntryType, sje.Status;
GO


-- =============================================================================
-- Block 6 (cont.) — vw_FxExposure read-model view.
--
-- Surfaces the FX position the subledger CAN see today from its own data: foreign-currency-denominated
-- JE lines (OriginalCurrencyCode set + ≠ the company's functional currency), netted per Company × currency,
-- with the booked functional value and — when a current spot rate exists — the implied unrealized FX delta.
--
-- Works with what we have now: JournalEntryLine carries OriginalCurrencyCode / OriginalDebit/CreditAmount /
-- ExchangeRateUsed; CurrencySpotRate carries the latest rate per pair. The reval CALC (whether the realized/
-- unrealized FX entry is generated here or in Payments) is still under discussion (W5 / §C1) — this view does
-- not generate anything; it reports the exposure. If CurrencySpotRate is unpopulated, CurrentSpotRate +
-- UnrealizedFxDelta are NULL and the view still shows the booked foreign-currency position (degrades cleanly).
-- =============================================================================

CREATE OR ALTER VIEW __mj_BizAppsAccounting.vw_FxExposure AS
WITH spot AS (
    -- latest active spot rate per (from,to) currency pair
    SELECT FromCurrencyCode, ToCurrencyCode, Rate,
           ROW_NUMBER() OVER (PARTITION BY FromCurrencyCode, ToCurrencyCode ORDER BY RateDate DESC) AS rn
    FROM __mj_BizAppsAccounting.CurrencySpotRate
    WHERE IsActive = 1
),
pos AS (
    -- net foreign-currency position per Company × original currency, over committed JE lines
    SELECT
        je.CompanyID,
        acp.FunctionalCurrencyCode,
        jel.OriginalCurrencyCode,
        SUM(ISNULL(jel.OriginalDebitAmount, 0) - ISNULL(jel.OriginalCreditAmount, 0)) AS NetOriginalAmount,
        SUM(ISNULL(jel.DebitAmount, 0)         - ISNULL(jel.CreditAmount, 0))         AS NetFunctionalBooked,
        COUNT(*)                                                                       AS LineCount
    FROM __mj_BizAppsAccounting.JournalEntryLine jel
    JOIN __mj_BizAppsAccounting.JournalEntry je ON je.ID = jel.JournalEntryID
    JOIN __mj_BizAppsAccounting.AccountingCompanyProfile acp ON acp.ID = je.CompanyID
    WHERE jel.OriginalCurrencyCode IS NOT NULL
      AND jel.OriginalCurrencyCode <> acp.FunctionalCurrencyCode   -- true foreign exposure only
      AND je.Status IN ('Batched', 'GLPosted')
    GROUP BY je.CompanyID, acp.FunctionalCurrencyCode, jel.OriginalCurrencyCode
)
SELECT
    pos.CompanyID,
    c.Name                          AS CompanyName,
    pos.FunctionalCurrencyCode,
    pos.OriginalCurrencyCode,
    pos.NetOriginalAmount,
    pos.NetFunctionalBooked,
    pos.LineCount,
    s.Rate                          AS CurrentSpotRate,
    -- exposure: foreign position valued at the current rate, less what was booked in functional terms.
    -- NULL until a spot rate exists for the pair (no fabricated number).
    CASE WHEN s.Rate IS NOT NULL
         THEN ROUND(pos.NetOriginalAmount * s.Rate - pos.NetFunctionalBooked, 2)
         ELSE NULL END              AS UnrealizedFxDelta
FROM pos
LEFT JOIN __mj.Company c ON c.ID = pos.CompanyID
LEFT JOIN spot s ON s.FromCurrencyCode = pos.OriginalCurrencyCode
                AND s.ToCurrencyCode = pos.FunctionalCurrencyCode
                AND s.rn = 1;
GO


-- =============================================================================
-- Block 6 (completion) — the previously-deferred read-model views.
--
-- The first read-model migration (V202606300300) shipped 6 views and listed 5 as DEFERRED.
-- On review the subledger's own committed schema DOES support all of them now — the earlier
-- "deferred" note was over-cautious. This migration delivers them. Reporting views (`vw_`
-- prefix, distinct from CodeGen's per-entity `vw<Entity>`); idempotent (CREATE OR ALTER),
-- additive-only; they are NOT entities (no CodeGen). Balances are computed ON DEMAND from
-- JournalEntryLine (per AD-12: AccountBalance* materialization is deferred to post-v1).
--
-- DELIVERED HERE:
--   vw_SalesTaxLiability  — accrued vs remitted tax per Company × Authority × Jurisdiction × Period
--   vw_IntercompanyFlow   — all legs of an intercompany flow, reassembled by JournalEntry.IntercompanyFlowID
--   vw_DefRevRollforward  — deferred-revenue opening/additions/releases/closing per Company × Period
--   vw_AROpenByCustomer   — open AR balance per customer (JournalEntryLine.CounterpartyOrganizationID)
--   vw_ARAging            — open AR bucketed by age per customer
--
-- ACCOUNT IDENTIFICATION: the AR / Deferred-Revenue / Sales-Tax control accounts are resolved via
-- AccountingCompanyProfile.{AROpenGLAccountID, DeferredRevenueGLAccountID, SalesTaxPayableGLAccountID}
-- (NOT by hardcoded code), so a company that re-points its control account stays correct.
--
-- KNOWN v1 LIMITATIONS (test/extend when the upstream systems land — Orders/Payments, Block 7+):
--   * AR aging uses JournalEntry.EffectiveDate as the age basis (JournalEntry has no invoice DueDate;
--     that is an upstream Orders concept). Precise invoice-level (open-item / FIFO settlement) aging
--     requires upstream invoice + payment-application data — NOT modeled in the subledger yet.
--   * vw_AROpenByCustomer / vw_ARAging are populated only once AR lines carry CounterpartyOrganizationID
--     (Orders/Payments emit these; the demo seed exercises them). They are correct + testable now.
--   * vw_IntercompanyFlow shows whatever IntercompanyFlowID-tagged legs exist; the net+batch ENGINE
--     (Block 3) is what produces them at scale. The view is read-only and independent of that engine.
--   * vw_SalesTaxLiability reads TaxLiability accrued/remitted balances; the tax CALCULATION provider
--     is Block 7 (tail). The view is correct against whatever TaxLiability rows exist.
-- =============================================================================

---------------------------------------------------------------------------
-- vw_SalesTaxLiability — accrued vs remitted sales-tax liability
---------------------------------------------------------------------------
CREATE OR ALTER VIEW __mj_BizAppsAccounting.vw_SalesTaxLiability AS
SELECT
    tl.CompanyID,
    c.Name                                         AS CompanyName,
    tl.TaxAuthorityID,
    ta.Code                                        AS AuthorityCode,
    ta.Name                                        AS AuthorityName,
    tl.TaxJurisdictionID,
    tj.Code                                        AS JurisdictionCode,
    tj.Name                                        AS JurisdictionName,
    tl.AccountingPeriodID,
    ap.FiscalYear,
    ap.PeriodType,
    ap.PeriodStart,
    ap.PeriodEnd,
    tl.AccruedAmount,
    tl.RemittedAmount,
    tl.AccruedAmount - tl.RemittedAmount           AS OutstandingLiability,
    tl.Status,
    tl.DueDate,
    tl.FilingFrequency
FROM __mj_BizAppsAccounting.TaxLiability tl
JOIN __mj_BizAppsAccounting.TaxAuthority ta    ON ta.ID = tl.TaxAuthorityID
JOIN __mj_BizAppsAccounting.TaxJurisdiction tj ON tj.ID = tl.TaxJurisdictionID
JOIN __mj_BizAppsAccounting.AccountingPeriod ap ON ap.ID = tl.AccountingPeriodID
LEFT JOIN __mj.Company c ON c.ID = tl.CompanyID;
GO

---------------------------------------------------------------------------
-- vw_IntercompanyFlow — reassemble every leg of a flow by IntercompanyFlowID
---------------------------------------------------------------------------
CREATE OR ALTER VIEW __mj_BizAppsAccounting.vw_IntercompanyFlow AS
SELECT
    je.IntercompanyFlowID,
    je.CompanyID,
    c.Name                                         AS CompanyName,
    je.ID                                          AS JournalEntryID,
    je.EntryNumber,
    je.EntryType,
    je.Status,
    je.EffectiveDate,
    jel.LineNumber,
    jel.CounterpartyOrganizationID,
    o.Name                                         AS CounterpartyName,
    gl.Code                                        AS GLAccountCode,
    gl.Name                                        AS GLAccountName,
    gl.AccountType,
    jel.DebitAmount,
    jel.CreditAmount,
    jel.Description                                AS LineDescription
FROM __mj_BizAppsAccounting.JournalEntry je
JOIN __mj_BizAppsAccounting.JournalEntryLine jel ON jel.JournalEntryID = je.ID
JOIN __mj_BizAppsAccounting.GLAccount gl         ON gl.ID = jel.GLAccountID
LEFT JOIN __mj_BizAppsCommon.Organization o      ON o.ID = jel.CounterpartyOrganizationID
LEFT JOIN __mj.Company c                          ON c.ID = je.CompanyID
WHERE je.IntercompanyFlowID IS NOT NULL;
GO

---------------------------------------------------------------------------
-- vw_DefRevRollforward — deferred-revenue rollforward (opening/additions/releases/closing)
--   Deferred Revenue is a liability (credit-normal): additions = credits (revenue deferred),
--   releases = debits (revenue recognized). Opening/closing are cumulative, computed on demand
--   from JournalEntryLine via window functions (AD-12 — no materialized balances).
--   Assumes JEs post to non-overlapping periods (normal month-grain posting).
---------------------------------------------------------------------------
CREATE OR ALTER VIEW __mj_BizAppsAccounting.vw_DefRevRollforward AS
WITH defrev AS (
    SELECT
        je.CompanyID,
        je.AccountingPeriodID,
        SUM(ISNULL(jel.CreditAmount, 0)) AS Additions,   -- revenue deferred (credit)
        SUM(ISNULL(jel.DebitAmount, 0))  AS Releases      -- revenue recognized (debit)
    FROM __mj_BizAppsAccounting.JournalEntry je
    JOIN __mj_BizAppsAccounting.JournalEntryLine jel ON jel.JournalEntryID = je.ID
    JOIN __mj_BizAppsAccounting.AccountingCompanyProfile acp ON acp.ID = je.CompanyID
    WHERE jel.GLAccountID = acp.DeferredRevenueGLAccountID
      AND je.Status IN ('Batched', 'GLPosted')
    GROUP BY je.CompanyID, je.AccountingPeriodID
)
SELECT
    d.CompanyID,
    c.Name                                         AS CompanyName,
    d.AccountingPeriodID,
    ap.FiscalYear,
    ap.PeriodType,
    ap.PeriodStart,
    ap.PeriodEnd,
    ISNULL(SUM(d.Additions - d.Releases) OVER (
        PARTITION BY d.CompanyID ORDER BY ap.PeriodStart
        ROWS BETWEEN UNBOUNDED PRECEDING AND 1 PRECEDING), 0)  AS OpeningBalance,
    d.Additions,
    d.Releases,
    d.Additions - d.Releases                       AS NetChange,
    SUM(d.Additions - d.Releases) OVER (
        PARTITION BY d.CompanyID ORDER BY ap.PeriodStart
        ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW)      AS ClosingBalance
FROM defrev d
JOIN __mj_BizAppsAccounting.AccountingPeriod ap ON ap.ID = d.AccountingPeriodID
LEFT JOIN __mj.Company c ON c.ID = d.CompanyID;
GO

---------------------------------------------------------------------------
-- vw_AROpenByCustomer — open AR balance per customer Organization
--   AR is an asset (debit-normal): open balance = SUM(Dr) - SUM(Cr) on the AR control account.
---------------------------------------------------------------------------
CREATE OR ALTER VIEW __mj_BizAppsAccounting.vw_AROpenByCustomer AS
SELECT
    je.CompanyID,
    c.Name                                                            AS CompanyName,
    jel.CounterpartyOrganizationID                                    AS CustomerOrganizationID,
    o.Name                                                            AS CustomerName,
    SUM(ISNULL(jel.DebitAmount, 0) - ISNULL(jel.CreditAmount, 0))      AS OpenBalance,
    SUM(ISNULL(jel.DebitAmount, 0))                                    AS TotalCharges,
    SUM(ISNULL(jel.CreditAmount, 0))                                   AS TotalPayments,
    COUNT(DISTINCT je.ID)                                              AS EntryCount
FROM __mj_BizAppsAccounting.JournalEntry je
JOIN __mj_BizAppsAccounting.JournalEntryLine jel ON jel.JournalEntryID = je.ID
JOIN __mj_BizAppsAccounting.AccountingCompanyProfile acp ON acp.ID = je.CompanyID
LEFT JOIN __mj_BizAppsCommon.Organization o ON o.ID = jel.CounterpartyOrganizationID
LEFT JOIN __mj.Company c ON c.ID = je.CompanyID
WHERE jel.GLAccountID = acp.AROpenGLAccountID
  AND je.Status IN ('Batched', 'GLPosted')
GROUP BY je.CompanyID, c.Name, jel.CounterpartyOrganizationID, o.Name
HAVING SUM(ISNULL(jel.DebitAmount, 0) - ISNULL(jel.CreditAmount, 0)) <> 0;
GO

---------------------------------------------------------------------------
-- vw_ARAging — open AR per customer bucketed by age (EffectiveDate basis, as of now/UTC)
---------------------------------------------------------------------------
CREATE OR ALTER VIEW __mj_BizAppsAccounting.vw_ARAging AS
WITH ar AS (
    SELECT
        je.CompanyID,
        jel.CounterpartyOrganizationID                            AS CustomerOrganizationID,
        DATEDIFF(DAY, je.EffectiveDate, CAST(SYSUTCDATETIME() AS DATE)) AS AgeDays,
        (ISNULL(jel.DebitAmount, 0) - ISNULL(jel.CreditAmount, 0)) AS NetAmount
    FROM __mj_BizAppsAccounting.JournalEntry je
    JOIN __mj_BizAppsAccounting.JournalEntryLine jel ON jel.JournalEntryID = je.ID
    JOIN __mj_BizAppsAccounting.AccountingCompanyProfile acp ON acp.ID = je.CompanyID
    WHERE jel.GLAccountID = acp.AROpenGLAccountID
      AND je.Status IN ('Batched', 'GLPosted')
)
SELECT
    ar.CompanyID,
    c.Name                                                                       AS CompanyName,
    ar.CustomerOrganizationID,
    o.Name                                                                       AS CustomerName,
    SUM(CASE WHEN ar.AgeDays <= 30                       THEN ar.NetAmount ELSE 0 END) AS Current_0_30,
    SUM(CASE WHEN ar.AgeDays BETWEEN 31 AND 60           THEN ar.NetAmount ELSE 0 END) AS Days_31_60,
    SUM(CASE WHEN ar.AgeDays BETWEEN 61 AND 90           THEN ar.NetAmount ELSE 0 END) AS Days_61_90,
    SUM(CASE WHEN ar.AgeDays > 90                        THEN ar.NetAmount ELSE 0 END) AS Days_Over_90,
    SUM(ar.NetAmount)                                                            AS TotalOpen
FROM ar
LEFT JOIN __mj_BizAppsCommon.Organization o ON o.ID = ar.CustomerOrganizationID
LEFT JOIN __mj.Company c ON c.ID = ar.CompanyID
GROUP BY ar.CompanyID, c.Name, ar.CustomerOrganizationID, o.Name
HAVING SUM(ar.NetAmount) <> 0;
GO


































































